var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"미나 양! 물러서세요!","JPN":"ミナさん！　下がってください！","ENG":"Mina! Fall back!","TWN":"米娜！走開！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"자칫하면 그림자들에게 포위당합니다!","JPN":"下手をすればシャドウに囲まれます！","ENG":"One wrong move and you’ll be surrounded by Shadows!","TWN":"萬一有個什麼差錯，你會被暗影包圍的！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"하지만…… 저기, 저기서 소대장과 싸우고 있는 건……","JPN":"けど……あれ、あそこで小隊長と戦っているのは……","ENG":"But... Th-the thing that the Commander is fighting...","TWN":"可是……在那裡和小隊長對打的……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"나잖아?","JPN":"私？","ENG":"...That’s me.","TWN":"不就是我嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"아니. 그렇지 않아.","JPN":"いや、そうじゃないよ。","ENG":"No, that’s not true.","TWN":"不，不是的。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"저건 부활의 지팡이로 만들어낸 육신에 세라펠의 실을 짜 넣어서 조종하는 인형일 뿐.","JPN":"あれは復活の杖が作り出した肉体にセラフェルの糸を編みこんで操られている人形に過ぎない。","ENG":"That’s merely a puppet created by stuffing a body made with the Staff of Resurrection with Serapel’s strings.","TWN":"那只是將塞拉費爾的線，放入以復活之杖製造出來的軀體中，再加以控制的木偶而已。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"네 피가 한 방울 섞여 있다는 건 인정하지만, 그건 반창고도 마찬가지지.","JPN":"君の血が1滴混じってはいるけど、それは絆創膏程度だよね。","ENG":"I admit that a drop of my blood is also mixed in, but the same could be said for a band-aid.","TWN":"雖然是有混到一滴你的血，但量就跟OK繃上的差不多。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"늑대의 긍지도 없는 저런 모조품을 우리라고 인정하지 마.","JPN":"狼の誇りもないあんな模造品を私たちだと思わないで。","ENG":"Don’t acknowledge such imitations that lack a Wolf’s pride as us.","TWN":"像那種完全沒有狼的自負的複製品，才不是我們！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌…… 또 여기야?","JPN":"あんた……またここなの？","ENG":"You’re... I’m here again?","TWN":"你……我怎麼又在這裡？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"그래. 결국 아무것도 모르는 채로 클리포트 게임의 열쇠를 돌려 버렸구나.","JPN":"そう。結局何も知らないままクリフォトゲームの扉を開けてしまったのね。","ENG":"Yeah, it looks like you’ve turned the key to the Qliphoth Game without knowing anything about it.","TWN":"沒錯，結果你還是在不知情的情況下，轉動了逆卡巴拉遊戲的鑰匙。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"하지만 넌 아직 준비가 되지 못했지.","JPN":"でも、君はまだ十分に準備ができていない。","ENG":"However, you’re not ready yet.","TWN":"可是你又還沒準備好，"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"불쌍한 나의 스승은…… 또 한 번 상처 받을 테고.","JPN":"かわいそうな師匠は……また傷つくだろうね。","ENG":"My poor master... She’ll get hurt again.","TWN":"我可憐的師父……又會經歷到二次傷害，"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"아무도 알아주지 않는 혼자만의 상처를.","JPN":"本人にしかわからないだろうけど。","ENG":"A scar that she will have to bear by herself.","TWN":"而且是只能獨自承受的傷害。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"무슨 뜻이야, 그건?","JPN":"どういうこと？","ENG":"What’s that supposed to mean?","TWN":"那是什麼意思？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"힐데 소대장이 상처를 받는다고? 고작 내 모습을 본딴 도플갱어와 싸우는 걸로?","JPN":"ヒルデ小隊長が傷つく？　私の姿を真似たドッペルゲンガーと戦って？","ENG":"Commander Hilde getting hurt? Just by fighting a Doppelganger with my appearance?","TWN":"希爾德小隊長會受傷？對手不過是模仿我的二重身而已欸？"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그럴 리가 없잖아.","JPN":"そんなはずないよ。","ENG":"There’s no way.","TWN":"這怎麼可能！"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌 잘 모르겠지만…… 우린 그렇게 친한 관계가 아니야.","JPN":"あんたはよくわからないけど……師匠とはそんなに親しい間柄じゃない。","ENG":"You may not know... But we aren’t that close with each other.","TWN":"你好像不太清楚……我們並沒有很熟。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"……아무것도 모르는 건 너야. 불쌍하게도.","JPN":"……何も知らないのは君の方だよ。かわいそうに。","ENG":"...You’re the one who knows nothing, you poor thing.","TWN":"……不清楚的是你，真是可憐。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"이 게임을 열었던 게 너로 인했듯이, 이 게임을 닫을 수 있는 자도 너뿐이다.","JPN":"このゲームを始めた原因が君だったように、このゲームを終わらせることができるのも君だけだ。","ENG":"Just as this game was started by you, only you can bring an end to it.","TWN":"這個遊戲是因你而開始的，能結束這個遊戲的也只有你。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"그리고 무한히 현세를 떠도는 최후의 발키리를 구원할 수 있는 것도……","JPN":"それから、とめどなく現世をさまようラストヴァルキリーを救えるのも……","ENG":"And perhaps save the Last Valkyrie who eternally wanders this world...","TWN":"包括拯救不斷在現世漂泊的最後的女武神……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"너무 늦기 전에…… 결정의 순간이 오기 전에……","JPN":"手遅れになる前に……決定する瞬間が来る前に……","ENG":"Before it’s too late... Before the decisive moment comes...","TWN":"在還來得及之前……在決定的瞬間到來之前……"},"stage":{"bg":"MIND","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_OTHER_QM","text":{"KOREA":"네가 준비되기를 기대하마.","JPN":"君の準備ができていることを期待する。","ENG":"I hope that you’ll be ready.","TWN":"希望你能準備好。"},"stage":{"bg":"MIND","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_OTHER_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"크윽……!!","JPN":"くうっ……！！","ENG":"Hngh!!","TWN":"唔……！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"멍하니 있지 말고 물러서, 신입!","JPN":"ぼうっとしていないで下がれ、新人！","ENG":"Don’t just stand there! Fall back, rookie!","TWN":"別傻楞著，閃開，新人！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"호오, 저게 내 남은 가장 큰 찌꺼기인가?","JPN":"へえ、あれが残っている中で一番大きなカス？","ENG":"Oh? Is that my largest remaining residue?","TWN":"呵，那是我留下的最大殘渣嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L31_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"이제 와서 저런 걸 숨겨 두고 있었다니, 너무 귀여운 짓이잖아. 나의 힐데.","JPN":"今になってあんなのを隠していたなんて、かわいいところがあるね。私のヒルデ。","ENG":"Hiding that away from me at this point of time... How cute, my Hilde.","TWN":"竟然還留一手，真是可愛呢，我的希爾德。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……시끄러워.","JPN":"……黙れ。","ENG":"Shut up...","TWN":"……閉嘴！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"하지만…… 조금 질투가 나는 건 어쩔 수 없는걸?","JPN":"でも……どうしても少々妬けちゃうな？","ENG":"However... I can’t help but feel a tinge of jealousy.","TWN":"不過……我還真是有點嫉妒呢？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_PRIDE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"나와 함께했던 그 모든 기억에도, 내가 겪었던 그 모든 희생에도 불구하고……","JPN":"私と共にしたすべての記憶、君が経験したすべての犠牲にもかかわらず……","ENG":"Despite all of our memories together, and all of the sacrifices that I made...","TWN":"你不顧我們過去的回憶，和我所經歷的一切犧牲……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"저런 찌꺼기를 위해 나를 막아서는 거야?","JPN":"あんなカスのために私の前に立ちはだかるの？","ENG":"You stand in my way for that residue?","TWN":"就因為她而要阻止我嗎？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"이래서야…… 나를 만들어낸 자들의 뜻대로 조종당할 뿐이라는 건 알고 있지만……","JPN":"これじゃ……私を作り出した者の思い通りに操られるだけだってわかってはいるけど……","ENG":"Now... I know that I’m merely being controlled by the ones who created me...","TWN":"我知道……我這麼做只是受控於那些創造我的人……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"역시 나도 어쩔 수 없는 도플갱어인가 봐.","JPN":"やっぱり私もドッペルゲンガーの性には抗えないみたい。","ENG":"But what can I do? I’m just a Doppelganger.","TWN":"但我果然是身不由己的二重身吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"네가 보는 앞에서, 저 찌꺼기를 갈기갈기 찢어 줄게.","JPN":"君が見ている前で、あのカスをずたずたに引き裂いてあげる。","ENG":"I’ll rip that residue apart in front of your eyes.","TWN":"我會在你眼前，將那個殘渣撕爛！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"어때? 20여 년만에 열리는 클리포트 게임의 서전에 딱 적당한 제물이지?","JPN":"どう？　20余年ぶりに開かれたクリフォトゲームの緒戦にふさわしい捧げものでしょ？","ENG":"What do you think? Isn’t she a fitting sacrifice to open the first Qliphoth Game in 20 years?","TWN":"如何？逆卡巴拉遊戲時隔20多年才啟動，她很適合拿來當作首戰的祭物吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"……지금 여기서 누군가가 찢겨진다면 그건 너뿐이다.","JPN":"……今ここで誰かが引き裂かれるというなら、それはお前だけだ。","ENG":"...If anyone is going to get ripped to pieces here, it’s you.","TWN":"……現在在這裡會被撕爛的，就只有你而已。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그런 모습으로, 말투로, 거짓된 추억으로 날 흔들 수 있다고 생각했겠지.","JPN":"その姿、話し方、偽りの思い出で私を揺さぶれると思ったのだろう。","ENG":"You may have thought that you would be able to shake my resolve with that appearance, tone and false memories.","TWN":"你以為用那張臉、那種語氣，和虛假的回憶，就可以動搖我是吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나를……. 상처 입힐 수 있다고 생각했겠지.","JPN":"私を……傷つけられると思っただろう。","ENG":"You may have thought that you could hurt me... with these.","TWN":"就可以……傷害我是吧？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"맞아. 그럴 거다.","JPN":"それは正しい。","ENG":"And you’re right, you can.","TWN":"沒錯，完全正確。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"하지만 그게 뭐 어쨌다는 거지?","JPN":"だが、それがどうしたというんだ？","ENG":"But what about it?","TWN":"但那又如何？"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"나는 이미 상처뿐인…… 아니, 상처 그 자체인 존재다.","JPN":"私はすでに傷だらけの……いや、傷そのものだ。","ENG":"I am already full of wounds... No, I am the wound itself.","TWN":"我早就只剩下傷害……不，我就是傷害的化身。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"내게도, 나와 연관된 자들에게도.","JPN":"私にとっても、私と関係のある者にとっても。","ENG":"I am the one who harms myself and those close to me.","TWN":"傷害我，傷害與我有關的人，"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"그러니 너, 내 과거의 추억에게도…… 상처를 안겨 주마!","JPN":"だから、お前、私の過去の思い出にも……傷を負わせてやる！","ENG":"Therefore, I’ll give you and my memories of the past with...!","TWN":"傷害我過去的回憶……"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"영원한 소멸이라는 상처를!!","JPN":"永遠の消滅という傷を！！","ENG":"A wound of eternal destruction!!","TWN":"你儘管讓這些都永遠消失吧！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"역시…… 아무것도 바뀌지 않았네.","JPN":"やっぱり……何も変わってないね。","ENG":"Nothing changed... As expected.","TWN":"果然……一點都沒變呢。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"조금 아쉽긴 하지만, 네가 그렇다면 나도 욕심을 조금은 접어야겠지.","JPN":"残念だけれど、君がそう出るなら私も欲を少し捨てないとね。","ENG":"Although a bit disappointing, if that’s your resolve, then I’ll also forgo some of my greed.","TWN":"雖然有點遺憾，但既然你這麼說，那我也稍微收斂一點。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_LAUGH"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"이 가짜 늑대의 송곳니가 부러지도록, 널 상대해 줄게.","JPN":"この偽りの狼の牙が壊れるほど、相手をしてあげる。","ENG":"I’ll fight you until this false Wolf’s fang breaks.","TWN":"就打到這假的狼牙斷掉為止吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"들어와, 나의 스승.","JPN":"おいで、私の師匠。","ENG":"Come, Master.","TWN":"回來吧，我的師父。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_PRIDE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"YOOMINA_ENERMY_NEXT_DOP","text":{"KOREA":"나의 힐데.","JPN":"私のヒルデ。","ENG":"My Hilde.","TWN":"我的希爾德。"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_ENERMY_NEXT_DOP","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"울어라!","JPN":"鳴け！","ENG":"Howl!","TWN":"咆哮吧！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HILDE_FENRIR_NEXT_NULL","text":{"KOREA":"레긴! 파프닐!!","JPN":"レギン！　ファフニール！！","ENG":"Regin! Fafnir!!","TWN":"雷金！帕夫尼爾！！"},"stage":{"bg":"COUNTERSIDE_RED","bgm":"BATTLE_COUNTERSIDE_ICELAND_NOAMB","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NEXT_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"제 6종급……! 에너지 충격파 발생!","JPN":"第6種レベル……！　エネルギー衝撃波発生！","ENG":"Category 6...! Energy shock wave detected!","TWN":"6類……！產生能量衝擊波！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"아줌마! 그림자 전당 차원 구조에 균열이 발생하고 있어!","JPN":"おばさん！　影の殿堂の次元構造に亀裂が入ってる！","ENG":"Maria! A rift is appearing within the dimensional structure of the Shadow Palaces!","TWN":"大嬸！暗影殿堂次元結構正在產生裂縫！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이대로 두면 모두 허수공간으로 빨려 나갈 거야!","JPN":"このままじゃ全員虚数空間に吸い込まれちゃうわ！","ENG":"We’ll all be sucked into the imaginary space if we don’t do anything about it!","TWN":"再這樣下去，所有人都會掉到虛數空間裡的！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"아니! 균열이 벌어지는 건 내가 막겠다!","JPN":"いや！　亀裂の広がりは私が防ぐ！","ENG":"No! I'll prevent the rift from opening!","TWN":"不可以！裂縫交給我來處理！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"MARIA_DELTA_NULL_NULL","text":{"KOREA":"룩!","JPN":"ルーク！","ENG":"Rook!","TWN":"城堡！"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MARIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"……알큐비에레 프로토콜 재접속.","JPN":"……アルクビエレプロトコル再接続。","ENG":"...Regaining access to Alcubierre Protocol.","TWN":"……重新連上協定引擎。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LOOK_REPLACER_NULL_NULL","text":{"KOREA":"시공가속기 가르강튀아, 시동.","JPN":"時空加速器ガルガンティア、起動。","ENG":"Time-space accelerator Garguantia, activated.","TWN":"時空加速器 加爾剛迪亞，啟動。"},"stage":{"bg":"PROLOGUE_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOOK_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};